import pg from 'pg';
const url = process.env.DATABASE_URL || 'postgres://codeleon:codeleon@postgres:5432/codeleon';
const client = new pg.Client({ connectionString: url });
await client.connect();
await client.query('CREATE TABLE IF NOT EXISTS notes (id SERIAL PRIMARY KEY, body TEXT NOT NULL)');
await client.query('INSERT INTO notes (body) VALUES ($1)', ['hello postgres']);
const result = await client.query('SELECT count(*)::int AS count FROM notes');
console.log(`postgres rows: ${result.rows[0].count}`);
await client.end();
